ided to `wp_set_object_terms()`.'=>'اینکه آیا عبارات در این طبقه بندی باید به ترتیبی که در «wp_set_object_terms()» ارائه شده است مرتب شوند.','Widget'=>'ابزارک','Widgets'=>'ابزارک‌ها','Width'=>'عرض','Wrapper Attributes'=>'مشخصات پوشش فیلد','Yes'=>'بله','Your license key is defined in wp-config.php.'=>'کلید مجوز شما در wp-config.php تعریف شده است.','Zoom'=>'بزرگنمایی','[ACF shortcode value disabled for preview]'=>'[مقدار کد کوتاه ACF برای پیش نمایش غیرفعال است]','and'=>'و','class'=>'کلاس','copy'=>'کپی','genre'=>'ژانر','https://wpengine.com/?utm_source=wordpress.org&utm_medium=referral&utm_campaign=plugin_directory&utm_content=advanced_custom_fields'=>'https://wpengine.com/?utm_source=wordpress.orghttps://wpengine.com/?utm_source=wordpress.org&utm_medium=referral&utm_campaign=plugin_directory&utm_content=advanced_custom_fields','https://www.advancedcustomfields.com'=>'https://www.advancedcustomfields.com','id'=>'شناسه','is developed and maintained by'=>'توسط توسعه و نگهداری می شود','is equal to'=>'برابر شود با','is not equal to'=>'برابر نشود با','layout'=>'طرح‌ها' . "\0" . 'طرح','layouts'=>'طرح ها','movie'=>'movie','nounClone'=>'کپی (هیچ)','nounSelect'=>'انتخاب','oEmbed'=>'oEmbed','or'=>'یا','paging%1$s of %2$s'=>'%1$s از %2$s','post statusActive'=>'فعال','post statusInactive'=>'غیرفعال','post statusRegistration Failed'=>'ثبت نام انجام نشد','post type'=>'نوع نوشته','red : Red'=>'red : قرمز','taxonomy'=>'طبقه‌بندی','verbEdit'=>'ویرایش','verbSelect'=>'انتخاب','verbUpdate'=>'بروزرسانی','width'=>'عرض','{available} {label} {identifier} available (max {max})'=>'{available} {label} {identifier} موجود است (حداکثر {max})','{required} {label} {identifier} required (min {min})'=>'{required} {label} {identifier} لازم دارد (حداقل {min})','← Go to %s'=>'← به %s بروید','← Go to tags'=>'← برو به برچسب ها']];
